DROP TABLE IF EXISTS `advertisement_performance`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `advertisement_performance` (
  `ad_performance_id` int NOT NULL AUTO_INCREMENT,
  `ad_id` int NOT NULL,
  `reported_date` date NOT NULL,
  `device` enum('Phone','Tablet','Desktop') NOT NULL,
  `impressions` int NOT NULL,
  `clicks` int NOT NULL,
  `conversions` int NOT NULL,
  `platform_ad_revenue` decimal(10,2) NOT NULL,
  PRIMARY KEY (`ad_performance_id`),
  KEY `ad_id` (`ad_id`),
  CONSTRAINT `advertisement_performance_ibfk_1` FOREIGN KEY (`ad_id`) REFERENCES `advertisements` (`ad_id`),
  CONSTRAINT `chk_clicks` CHECK ((`clicks` <= `impressions`)),
  CONSTRAINT `chk_conversions` CHECK ((`conversions` <= `clicks`))
) ENGINE=InnoDB AUTO_INCREMENT=1907 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
