  `min_spend` decimal(10,2) DEFAULT NULL,
  `discount_start_date` date NOT NULL,
  `discount_end_date` date DEFAULT NULL,
  PRIMARY KEY (`discount_id`),
  KEY `campaign_id` (`campaign_id`),
  CONSTRAINT `discounts_ibfk_1` FOREIGN KEY (`campaign_id`) REFERENCES `campaigns` (`campaign_id`),
  CONSTRAINT `discounts_chk_1` CHECK ((`discount_value` >= 0)),
  CONSTRAINT `discounts_chk_2` CHECK (((`discount_type` <> 'Percentage') or (`discount_value` <= 100))),
  CONSTRAINT `discounts_chk_3` CHECK (((`min_spend` is null) or (`min_spend` >= 0)))
) ENGINE=InnoDB AUTO_INCREMENT=51 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
